import { estimatedWithProfileTags, type NutritionEstimateProfile } from "./estimationProfiles";
import { unofficial } from "./helpers";

type GenericEstimateInput = Omit<Parameters<typeof estimatedWithProfileTags>[0], "profile">;

const hasAny = (text: string, words: string[]) => words.some((word) => text.includes(word));

const inferGenericProfile = (input: GenericEstimateInput): NutritionEstimateProfile => {
  const text = `${input.name} ${input.category} ${input.tags.join(" ")} ${input.serving_label ?? ""}`;

  if (input.category === "サプリ" || input.category === "プロテイン") return "supplement";
  if (hasAny(text, ["アルコール", "ビール", "ハイボール", "サワー", "日本酒", "焼酎", "ワイン", "ウイスキー", "梅酒", "マッコリ"])) return "alcohol";
  if (hasAny(text, ["プロテイン", "EAA", "BCAA", "グルタミン", "HMB"])) return "supplement";

  if (input.category === "ドリンク") {
    if (hasAny(text, ["牛乳", "豆乳", "ラテ", "ミルク"])) return "dairy";
    return "drink";
  }

  if (input.category === "ごはん・丼") {
    if (hasAny(text, ["カレー", "ビリヤニ"])) return "curryRice";
    if (hasAny(text, ["寿司", "海鮮", "まぐろ", "サーモン", "刺身", "ネギトロ"])) return "sushiRiceBowl";
    if (hasAny(text, ["おにぎり", "おむすび", "いなり"])) return "onigiri";
    if (hasAny(text, ["白米", "玄米", "ご飯", "ライス", "赤飯", "炊き込み", "混ぜご飯", "菜飯"])) return "plainRice";
    if (hasAny(text, ["チャーハン", "炒飯"])) return "friedRice";
    return "riceBowl";
  }

  if (input.category === "麺類") {
    if (hasAny(text, ["つけ麺"])) return "tsukemen";
    if (hasAny(text, ["ラーメン", "担々麺", "坦々麺", "油そば", "冷やし中華"])) return "ramen";
    if (hasAny(text, ["パスタ", "スパゲッティ", "ナポリタン"])) {
      if (hasAny(text, ["クリーム", "カルボナーラ"])) return "creamPasta";
      if (hasAny(text, ["ペペロンチーノ", "オイル", "ジェノベーゼ"])) return "oilPasta";
      return "pasta";
    }
    return "sobaNoodle";
  }

  if (input.category === "パン") {
    if (hasAny(text, ["ピザ"])) return "pizza";
    if (hasAny(text, ["菓子パン", "甘い", "デニッシュ", "チョコ", "クリーム", "あんぱん"])) return "snack";
    return "bread";
  }

  if (input.category === "肉・魚") {
    if (hasAny(text, ["卵", "玉子", "納豆", "豆腐", "冷奴", "サラダチキン", "ツナ缶", "シーチキン", "缶"])) return "proteinTopping";
    if (hasAny(text, ["刺身", "鮭", "サバ", "さば", "魚", "イワシ"])) return "fishSetMeal";
    if (hasAny(text, ["唐揚げ", "竜田", "フライ", "揚げ", "カツ", "ナゲット"])) return "friedSide";
    if (hasAny(text, ["焼肉", "ステーキ", "ハンバーグ"])) return "steakPlate";
    return "meatSetMeal";
  }

  if (input.category === "サラダ・野菜") {
    if (hasAny(text, ["サラダ"])) return "salad";
    return "vegetableSide";
  }

  if (input.category === "スープ") return "soup";

  if (input.category === "おかず・惣菜") {
    if (hasAny(text, ["唐揚げ", "竜田", "フライ", "揚げ", "カツ", "天ぷら", "コロッケ"])) return "friedSide";
    if (hasAny(text, ["サラダ", "野菜", "おひたし", "和え", "きんぴら", "漬物"])) return "vegetableSide";
    if (hasAny(text, ["卵", "玉子", "豆腐", "納豆", "チーズ"])) return "proteinTopping";
    if (hasAny(text, ["魚", "鮭", "サバ", "さば", "刺身"])) return "fishSetMeal";
    if (hasAny(text, ["餃子"])) return "gyoza";
    return "meatSetMeal";
  }

  if (input.category === "スイーツ") {
    if (hasAny(text, ["果物", "バナナ", "りんご", "オレンジ", "ベリー", "ぶどう"])) return "fruit";
    if (hasAny(text, ["ナッツ", "ポテチ", "スナック", "せんべい", "柿の種", "チョコ", "グミ", "キャンディ", "菓子"])) return "snack";
    return "dessert";
  }

  return "riceSetMeal";
};

const genericEstimated = (input: GenericEstimateInput) =>
  estimatedWithProfileTags({
    ...input,
    tags: [...input.tags, "汎用推定"],
    profile: inferGenericProfile(input),
  });

